"""Pipeline data schema.

Defines the canonical field names and types for the data pipeline.
All modules must use these field names consistently.
"""

FIELDS = ["name", "age", "city", "score"]

FIELD_TYPES = {
    "name": str,
    "age": int,
    "city": str,
    "score": float,
}

REQUIRED_FIELDS = ["name", "age"]

DEFAULTS = {
    "city": "unknown",
    "score": 0.0,
}


def validate_field(name: str, value) -> bool:
    """Check if a value matches the expected type for a field."""
    if name not in FIELD_TYPES:
        return False
    expected_type = FIELD_TYPES[name]
    try:
        expected_type(value)
        return True
    except (ValueError, TypeError):
        return False

