"""Data transformation module.

Filters and transforms validated data rows.
Uses positional access to match the CSV-style format.
"""
from typing import List, Callable, Optional


class DataTransformer:
    """Transforms data rows using positional access."""

    def __init__(self):
        self._filters = []
        self._transforms = []

    def add_filter(self, fn: Callable) -> None:
        """Add a filter function. Rows where fn(row) is False are dropped."""
        self._filters.append(fn)

    def add_transform(self, fn: Callable) -> None:
        """Add a transform function applied to each row."""
        self._transforms.append(fn)

    def transform(self, rows: List[list]) -> List[list]:
        """Apply filters and transforms to rows.

        Args:
            rows: List of [name, age, city, score] rows

        Returns:
            Transformed list of rows
        """
        result = []
        for row in rows:
            # Apply filters
            skip = False
            for f in self._filters:
                if not f(row):
                    skip = True
                    break
            if skip:
                continue

            # Apply transforms
            current = row
            for t in self._transforms:
                current = t(current)

            result.append(current)
        return result

    @staticmethod
    def normalize_names(row: list) -> list:
        """Capitalize the name field (position 0)."""
        result = list(row)
        result[0] = str(row[0]).title()
        return result

    @staticmethod
    def clamp_score(row: list, min_val: float = 0.0, max_val: float = 100.0) -> list:
        """Clamp score (position 3) to [min_val, max_val]."""
        result = list(row)
        score = float(row[3])
        result[3] = max(min_val, min(max_val, score))
        return result

    @staticmethod
    def uppercase_city(row: list) -> list:
        """Uppercase the city field (position 2)."""
        result = list(row)
        result[2] = str(row[2]).upper()
        return result

    @staticmethod
    def age_bracket(row: list) -> list:
        """Add age bracket info by modifying the name field (position 0)."""
        result = list(row)
        age = int(row[1])
        name = str(row[0])
        if age < 18:
            result[0] = f"{name} (minor)"
        elif age < 65:
            result[0] = f"{name} (adult)"
        else:
            result[0] = f"{name} (senior)"
        return result

    @staticmethod
    def filter_adults(row: list) -> bool:
        """Filter: keep only rows where age (position 1) >= 18."""
        return int(row[1]) >= 18

    @staticmethod
    def filter_high_score(row: list, threshold: float = 50.0) -> bool:
        """Filter: keep only rows where score (position 3) >= threshold."""
        return float(row[3]) >= threshold

seed_files.writer.py:
"""Data writer module.

Formats and outputs processed data rows.
Uses positional access to match the CSV-style format.
"""
from typing import List, Optional
import json


class DataWriter:
    """Writes data rows to various output formats using positional access."""

    def __init__(self, format_type: str = "csv"):
        self._format_type = format_type
        self._output = []

    def write(self, rows: List[list]) -> str:
        """Write rows to the configured format.

        Args:
            rows: List of [name, age, city, score] rows

        Returns:
            Formatted output string
        """
        if self._format_type == "csv":
            return self._write_csv(rows)
        elif self._format_type == "json":
            return self._write_json(rows)
        elif self._format_type == "table":
            return self._write_table(rows)
        else:
            raise ValueError(f"Unknown format: {self._format_type}")

    def _write_csv(self, rows: List[list]) -> str:
        """Write rows as CSV."""
        lines = ["name,age,city,score"]
        for row in rows:
            line = f"{row[0]},{row[1]},{row[2]},{row[3]}"
            lines.append(line)
        output = "\n".join(lines)
        self._output.append(output)
        return output

    def _write_json(self, rows: List[list]) -> str:
        """Write rows as JSON array."""
        records = []
        for row in rows:
            records.append({
                "name": row[0],
                "age": row[1],
                "city": row[2],
                "score": row[3],
            })
        output = json.dumps(records, indent=2)
        self._output.append(output)
        return output

    def _write_table(self, rows: List[list]) -> str:
        """Write rows as a formatted table."""
        header = f"{'Name':<20} {'Age':>5} {'City':<15} {'Score':>8}"
        sep = "-" * len(header)
        lines = [header, sep]
        for row in rows:
            line = f"{str(row[0]):<20} {str(row[1]):>5} {str(row[2]):<15} {float(row[3]):>8.1f}"
            lines.append(line)
        output = "\n".join(lines)
        self._output.append(output)
        return output

    def get_history(self) -> List[str]:
        """Return all previous outputs."""
        return list(self._output)

    def clear_history(self) -> None:
        """Clear output history."""
        self._output = []
